using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    // Sort edges by time to process them in order
    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

    // Build adjacency list
    vector<vector<pair<long long, long long>>> adj(n);
    for (auto& edge : edges) {
        adj[edge[0]].emplace_back(edge[1], edge[2]);
        adj[edge[1]].emplace_back(edge[0], edge[2]);
    }

    // Union-Find data structure
    vector<long long> parent(n);
    vector<long long> rank(n, 1);

    // Function to find the root of a node
    auto find = [&](long long x) -> long long {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    // Function to perform union of two sets
    auto union_set = [&](long long x, long long y) -> bool {
        long long root_x = find(x);
        long long root_y = find(y);
        if (root_x == root_y) {
            return false; // Already in the same set
        }
        if (rank[root_x] < rank[root_y]) {
            parent[root_x] = root_y;
        } else {
            parent[root_y] = root_x;
            if (rank[root_x] == rank[root_y]) {
                rank[root_x]++;
            }
        }
        return true;
    };

    // Initialize parent array
    for (long long i = 0; i < n; ++i) {
        parent[i] = i;
    }

    // Process edges in order of increasing time
    long long result = 0;
    long long components = n; // Initially, each node is its own component

    for (auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long time = edge[2];

        // If the nodes are in different sets, union them
        if (union_set(u, v)) {
            components--;
        }

        // Check if we have at least k components
        if (components >= k) {
            result = time;
            break;
        }
    }

    // If we haven't found a time yet, return 0 (already have enough components)
    return result;
}

